mapper.select:
select cp.id, cp.create_time, cp.product_name, cp.product_code, cp.product_pics, cp.min_price, cp.if_shipped, cp.logistic_id, cp.shelve_area,cp.shelve_state, cp.shelve_area, cp.brand_name, cp.product_classify, cp.product_specs, cp.labels, cp.merchant_id, cmi.merchant_name, cp.product_text from cm_product cp left join cm_merchant_info cmi on cp.merchant_id = cmi.id where cp.deleted = '0' and cmi.deleted = '0'
and cp.merchant_id = #{vo.merchantId}
and cp.product_name like concat('%', #{vo.productName}, '%')
and cp.product_classify like concat('%', #{vo.productClassify}, '%')
and cp.shelve_state = #{vo.shelveState}
and cp.shelve_area = #{vo.shelveArea}
and cp.min_price >= cast(#{vo.minPrice} as DECIMAL)
and cp.min_price < cast(#{vo.maxPrice} as DECIMAL)
order by cp.create_time desc

select id, product_name, product_code, brand_name, product_classify
from cm_product where deleted = '0' and merchant_id = #{merchantId}
order by create_time desc

mapper.update:
update cm_product


		shelve_state = #{vo.shelveState},


		shelve_area = #{vo.shelveArea}


where id = #{vo.id}
